documentation.value:
The standard output stream object.

```cpp
std::cout << "Hello" << std::endl;
std::cout << "x = " << x << '\n';
```

The standard input stream object.

```cpp
int x;
std::cin >> x;
std::string line;
std::getline(std::cin, line);
```

Reads a full line from an input stream into a string.

```cpp
std::string line;
std::getline(std::cin, line);
std::getline(std::cin, line, ','); // custom delimiter
```

Dynamic character string with automatic memory management.

```cpp
std::string s = "hello";
std::string s2(5, 'a'); // "aaaaa"
s.append(" world");
std::cout << s.size() << std::endl;
```

Sequence container with dynamic contiguous storage.

```cpp
std::vector<int> v = {1, 2, 3};
v.push_back(4);
v.emplace_back(5);
for (auto& x : v) std::cout << x;
```

Sorted key-value container using a red-black tree.

```cpp
std::map<std::string, int> m;
m["apple"] = 1;
m.insert({"banana", 2});
for (auto& [key, val] : m) { ... }
```

Unordered key-value container using hash table. O(1) average lookup.

```cpp
std::unordered_map<std::string, int> m;
m["key"] = 42;
if (m.count("key")) { ... }
auto it = m.find("key");
```

Sorted container of unique elements (red-black tree).

```cpp
std::set<int> s = {3, 1, 4, 1, 5};
s.insert(9);
if (s.count(3)) { ... }
for (auto& x : s) std::cout << x;
```

Unordered container of unique elements using hash table.

```cpp
std::unordered_set<std::string> s;
s.insert("hello");
if (s.contains("hello")) { ... } // C++20
```

Fixed-size array with STL interface. Stack-allocated.

```cpp
std::array<int, 5> a = {1, 2, 3, 4, 5};
a[0] = 10;
std::cout << a.size(); // 5
std::sort(a.begin(), a.end());
```

Double-ended queue with efficient insertion/removal at both ends.

```cpp
std::deque<int> d = {1, 2, 3};
d.push_front(0);
d.push_back(4);
d.pop_front();
```

Doubly-linked list with O(1) insertion/removal anywhere.

```cpp
std::list<int> lst = {1, 2, 3};
lst.push_back(4);
lst.push_front(0);
lst.sort();
```

Container adapter providing LIFO (last-in, first-out) access.

```cpp
std::stack<int> s;
s.push(1);
s.push(2);
int top = s.top(); // 2
s.pop();
```

Container adapter providing FIFO (first-in, first-out) access.

```cpp
std::queue<int> q;
q.push(1);
q.push(2);
int front = q.front(); // 1
q.pop();
```

Container adapter providing priority-based access (max-heap).

```cpp
std::priority_queue<int> pq;
pq.push(3); pq.push(1); pq.push(4);
int top = pq.top(); // 4
// Min-heap:
std::priority_queue<int, std::vector<int>, std::greater<int>> minpq;
```

Holds two heterogeneous objects as a single unit.

```cpp
std::pair<int, std::string> p = {1, "hello"};
auto p2 = std::make_pair(42, 3.14);
std::cout << p.first << " " << p.second;
```

Holds a fixed number of heterogeneous values.

```cpp
std::tuple<int, double, std::string> t = {1, 3.14, "hi"};
auto [a, b, c] = t; // structured bindings
std::cout << std::get<0>(t);
```

Sorts elements in [first, last) range. Average O(n log n).

```cpp
std::vector<int> v = {3, 1, 4, 1, 5};
std::sort(v.begin(), v.end());
std::sort(v.begin(), v.end(), std::greater<>()); // descending
std::sort(v.begin(), v.end(), [](int a, int b) { return a > b; });
```

Finds the first element equal to the given value.

```cpp
std::vector<int> v = {1, 2, 3, 4};
auto it = std::find(v.begin(), v.end(), 3);
if (it != v.end()) { /* found */ }
```

Applies a function to each element in [first, last).

```cpp
std::vector<int> v = {1, 2, 3};
std::for_each(v.begin(), v.end(), [](int x) {
    std::cout << x << ' ';
});
```

Applies a function and stores the result in a destination range.

```cpp
std::vector<int> v = {1, 2, 3};
std::vector<int> result(v.size());
std::transform(v.begin(), v.end(), result.begin(), [](int x) {
    return x * 2;
});
```

Computes the sum (or custom fold) of elements in a range.

```cpp
#include <numeric>
std::vector<int> v = {1, 2, 3, 4};
int sum = std::accumulate(v.begin(), v.end(), 0);
int product = std::accumulate(v.begin(), v.end(), 1, std::multiplies<>());
```

Moves elements not satisfying the predicate to the front. Use with erase (erase-remove idiom).

```cpp
std::vector<int> v = {1, 2, 3, 4, 5};
v.erase(std::remove_if(v.begin(), v.end(), [](int x) { return x % 2 == 0; }), v.end());
// v = {1, 3, 5}
```

Removes consecutive duplicate elements. Typically used after sorting.

```cpp
std::vector<int> v = {1, 1, 2, 2, 3};
auto last = std::unique(v.begin(), v.end());
v.erase(last, v.end()); // v = {1, 2, 3}
```

Reverses the order of elements in [first, last).

```cpp
std::vector<int> v = {1, 2, 3, 4};
std::reverse(v.begin(), v.end()); // {4, 3, 2, 1}
```

Returns an iterator to the smallest element in [first, last).

```cpp
std::vector<int> v = {3, 1, 4, 1, 5};
auto it = std::min_element(v.begin(), v.end());
std::cout << *it; // 1
```

Returns an iterator to the largest element in [first, last).

```cpp
std::vector<int> v = {3, 1, 4, 1, 5};
auto it = std::max_element(v.begin(), v.end());
std::cout << *it; // 5
```

Returns iterator to the first element not less than value in a sorted range.

```cpp
std::vector<int> v = {1, 2, 4, 5, 6};
auto it = std::lower_bound(v.begin(), v.end(), 3);
// *it == 4
```

Returns iterator to the first element greater than value in a sorted range.

```cpp
std::vector<int> v = {1, 2, 3, 3, 5};
auto it = std::upper_bound(v.begin(), v.end(), 3);
// *it == 5
```

Smart pointer with exclusive ownership semantics. Cannot be copied.

```cpp
auto ptr = std::make_unique<int>(42);
std::unique_ptr<MyClass> p(new MyClass());
std::cout << *ptr;
ptr.reset(); // release ownership
```

Smart pointer with shared (reference-counted) ownership.

```cpp
auto ptr = std::make_shared<int>(42);
std::shared_ptr<MyClass> p2 = ptr; // refcount = 2
std::cout << ptr.use_count();
```

Non-owning reference to a `std::shared_ptr`-managed object. Breaks circular references.

```cpp
std::shared_ptr<int> sp = std::make_shared<int>(10);
std::weak_ptr<int> wp = sp;
if (auto locked = wp.lock()) {
    std::cout << *locked;
}
```

Creates a `std::unique_ptr` with a new heap-allocated object.

```cpp
auto p = std::make_unique<int>(42);
auto obj = std::make_unique<MyClass>(arg1, arg2);
auto arr = std::make_unique<int[]>(10); // array of 10
```

Creates a `std::shared_ptr` with a single allocation for object and control block.

```cpp
auto p = std::make_shared<int>(42);
auto obj = std::make_shared<MyClass>(arg1, arg2);
```

Casts its argument to an rvalue reference, enabling move semantics.

```cpp
std::string s = "hello";
std::string s2 = std::move(s); // s is now in a moved-from state
vec.push_back(std::move(obj));
```

Forwards lvalues as lvalues and rvalues as rvalues (perfect forwarding).

```cpp
template<typename T>
void wrapper(T&& arg) {
    inner(std::forward<T>(arg));
}
```

Manages an optional contained value (may or may not hold a value).

```cpp
std::optional<int> opt = 42;
if (opt.has_value()) std::cout << *opt;
std::optional<std::string> empty = std::nullopt;
auto val = opt.value_or(0);
```

Type-safe discriminated union. Holds one of several alternative types.

```cpp
std::variant<int, double, std::string> v = "hello";
std::cout << std::get<std::string>(v);
std::visit([](auto&& arg) { std::cout << arg; }, v);
```

Type-safe container for single values of any type.

```cpp
std::any a = 42;
a = std::string("hello");
std::string s = std::any_cast<std::string>(a);
```

Polymorphic function wrapper. Stores any callable target.

```cpp
std::function<int(int, int)> add = [](int a, int b) { return a + b; };
std::function<void()> callback = &myFunc;
std::cout << add(2, 3); // 5
```

Type-safe string formatting (Python-style).

```cpp
#include <format>
std::string s = std::format("Hello, {}! x = {:.2f}", name, 3.14159);
std::cout << std::format("{:>10}", "right");
```

A lightweight non-owning view over a contiguous sequence of objects.

```cpp
void process(std::span<int> data) {
    for (auto x : data) std::cout << x;
}
std::vector<int> v = {1, 2, 3};
process(v);
int arr[] = {4, 5, 6};
process(arr);
```

Specifies that a value or function can be evaluated at compile time.

```cpp
constexpr int square(int x) { return x * x; }
constexpr auto val = square(5); // evaluated at compile time
static_assert(square(3) == 9);
```

Compile-time conditional statement. Discards the false branch at compile time.

```cpp
template<typename T>
void process(T val) {
    if constexpr (std::is_integral_v<T>) {
        std::cout << "integer: " << val;
    } else {
        std::cout << "other: " << val;
    }
}
```

Declares a class type (members default to private).

```cpp
class MyClass {
public:
    MyClass() = default;
    void method();
private:
    int data_;
};
```

Declares a struct type (members default to public).

```cpp
struct Point {
    double x;
    double y;
};
```

Declares a namespace scope.

```cpp
namespace mylib {
    void func();
    class Widget {};
}
namespace mylib::detail { /* nested C++17 */ }
```

Declares a virtual (polymorphic) member function.

```cpp
class Base {
public:
    virtual void draw() { /* default */ }
    virtual ~Base() = default;
};
```

Ensures a function overrides a virtual function in a base class.

```cpp
class Derived : public Base {
public:
    void draw() override { /* ... */ }
};
```

Specifies that an object/variable cannot be modified.

```cpp
const int x = 42;
const std::string& ref = str;
void method() const; // does not modify *this
```

Specifies that a function does not throw exceptions.

```cpp
void func() noexcept;
void cond_func() noexcept(sizeof(int) >= 4);
bool is_ne = noexcept(func()); // operator form
```

Prevents implicit conversions or copy-initialization for constructors.

```cpp
class Foo {
public:
    explicit Foo(int x);
    explicit operator bool() const;
};
```

Allows modification of a member even in a const context.

```cpp
class Cache {
    mutable std::map<int, int> cache_;
public:
    int get(int key) const { cache_[key]++; return cache_[key]; }
};
```

Grants a function or class access to private/protected members.

```cpp
class MyClass {
    friend class OtherClass;
    friend std::ostream& operator<<(std::ostream&, const MyClass&);
};
```

Introduces names from namespaces or creates type aliases.

```cpp
using std::cout;
using namespace std;
using StringVec = std::vector<std::string>;
template<typename T> using Vec = std::vector<T>;
```

The null pointer literal (type `std::nullptr_t`).

```cpp
int* p = nullptr;
if (p == nullptr) { /* ... */ }
void func(int*); func(nullptr);
```

Performs compile-time checked type conversion.

```cpp
double d = 3.14;
int i = static_cast<int>(d);
Base* b = static_cast<Base*>(derived_ptr);
```

Performs runtime-checked polymorphic type conversion.

```cpp
Base* b = getBase();
Derived* d = dynamic_cast<Derived*>(b);
if (d) { /* safe to use d */ }
```

Performs low-level reinterpretation of bit patterns.

```cpp
int i = 42;
void* p = reinterpret_cast<void*>(&i);
auto fp = reinterpret_cast<void(*)(int)>(addr);
```

**Warning:** Potentially unsafe. Use only when necessary.

Generates a full class definition skeleton.

```cpp
class MyClass {
public:
    MyClass();
    ~MyClass();
private:
    int member_;
};
```

Generates a template class skeleton.

```cpp
template<typename T>
class Container {
public:
    void add(const T& item);
private:
    std::vector<T> items_;
};
```

Generates a range-based for loop.

```cpp
for (const auto& item : container) {
    // process item
}
```

Generates a lambda expression.

```cpp
auto fn = [](int x) { return x * 2; };
auto fn2 = [&](auto x) { return x + offset; };
```

Generates a try-catch exception handling block.

```cpp
try {
    // risky code
} catch (const std::exception& e) {
    std::cerr << e.what();
}
```

Creates a smart pointer using make_unique or make_shared.

```cpp
auto ptr = std::make_unique<MyClass>(args...);
auto sptr = std::make_shared<MyClass>(args...);
```

Generates the main function entry point.

```cpp
int main(int argc, char* argv[]) {
    return 0;
}
```

