Suspends a coroutine and waits for a result.

```cpp
task<int> fetch_data() {
    auto result = co_await async_read();
    co_return result;
}
```

Defines a named set of constraints for template arguments.

```cpp
template<typename T>
concept Addable = requires(T a, T b) {
    { a + b } -> std::convertible_to<T>;
};

template<Addable T>
T add(T a, T b) { return a + b; }
```

Composable lazy range adaptors.

```cpp
#include <ranges>
namespace rv = std::ranges::views;
auto evens = v | rv::filter([](int x) { return x % 2 == 0; });
auto squares = v | rv::transform([](int x) { return x * x; });
auto first5 = v | rv::take(5);
```

Decompose an object into named variables.

```cpp
auto [x, y] = std::make_pair(1, 2);
for (auto& [key, value] : myMap) {
    std::cout << key << ": " << value;
}
```

Include a header file.

```cpp
#include <iostream>
#include <vector>
#include "myheader.h"
```

Declares a scoped (strongly-typed) enumeration.

```cpp
enum class Color : uint8_t {
    Red,
    Green,
    Blue
};
Color c = Color::Red;
```

Asserts a condition at compile time.

```cpp
static_assert(sizeof(int) >= 4, "int must be at least 4 bytes");
static_assert(std::is_integral_v<int>);
```

Manages a separate thread of execution.

```cpp
#include <thread>
std::thread t([]{ std::cout << "Hello from thread"; });
t.join();
// or t.detach();
```

Provides mutual exclusion for protecting shared data.

```cpp
#include <mutex>
std::mutex mtx;
{
    std::lock_guard<std::mutex> lock(mtx);
    // critical section
}
```

RAII wrapper that locks a mutex on construction and unlocks on destruction.

```cpp
std::mutex mtx;
{
    std::lock_guard<std::mutex> lock(mtx);
    // safe access to shared data
}
```
